// Pipeline JSON arrives directly from HTTP Request (no binary parsing needed)
const pipeline = $input.first().json;
const scenes = pipeline.scenes || [];
const episodeId = pipeline.episode_id || 'EP-001';

// ── Structured prompt slot constants (style-first, no negatives) ──
// Medium FIRST — sets generation mode before scene content
const MEDIUM = '2D cel-shaded illustration, flat color fills, clean ink outlines, hand-drawn animation frame';
const TEXTURE = '35mm film grain 20% opacity, high contrast, shallow depth of field';
const FORMAT = '16:9 widescreen, cinematic composition';

// ── Act-keyed palette & lighting (narrative arc drives emotional temperature) ──
const ACT_MOOD = {
  ACT_1: {
    palette: 'Dark steel #1E1E20 dominant, rust-orange #9A4C22 sodium vapor only. Desaturated, muted, cold',
    lighting: 'Single rust-orange sodium vapor light source, Roger Deakins cinematography, dramatic hard shadows, heavy vignette'
  },
  ACT_2A: {
    palette: 'Dark steel #1E1E20 base, rust-orange #9A4C22 sodium vapor, neon accent bleeds from signage. Desaturated with pops of neon color',
    lighting: 'Sodium vapor primary light, neon sign color spill, harsh urban shadows, heavy vignette'
  },
  ACT_2B: {
    palette: 'Dark steel #1E1E20 softened, warm golden #D4A843 accent bleeding in, amber tones, honey highlights. Warmth emerging from darkness',
    lighting: 'Warm practical light from interior sources — barber lamps, kitchen windows, porch lights. Softer shadows, medium vignette'
  },
  ACT_2C: {
    palette: 'Dark steel #1E1E20 receding, warm golden #D4A843 dominant, amber and honey tones, late afternoon warmth. Community and conviction',
    lighting: 'Golden hour directional light, long warm shadows, medium vignette. Hopeful but grounded'
  },
  ACT_3A: {
    palette: 'Dark steel #1E1E20 with warm amber #C4873B candlelight, sepia undertones, aged paper warmth. Reverent and historical',
    lighting: 'Warm candlelight glow, soft amber directional light, gentle shadows, light vignette'
  },
  ACT_3B: {
    palette: 'Dark steel #1E1E20 foundation, warm golden #D4A843 and dawn orange, bone white #E7E7E1 highlights expanding. Practical hope',
    lighting: 'Early morning dawn light, warm and expanding, practical interior lighting, light vignette. Confident and clear'
  },
  UNKNOWN: {
    palette: 'Dark steel #1E1E20, rust-orange #9A4C22 sodium vapor accent, desaturated earth tones',
    lighting: 'Single rust-orange sodium vapor light source, dramatic hard shadows, heavy vignette'
  }
};

// ── Strip existing style cues from pipeline visual_prompt (they now live in slots) ──
function cleanScenePrompt(raw) {
  return raw
    .replace(/,?\s*2D cel-shaded style/gi, '')
    .replace(/,?\s*film grain \d+%/gi, '')
    .replace(/,?\s*heavy vignette/gi, '')
    .replace(/,?\s*16:9\.?/gi, '')
    .replace(/,?\s*1920x1080\.?/gi, '')
    .replace(/,?\s*Dark steel palette/gi, '')
    .replace(/,?\s*Rust[- ]orange and dark steel only/gi, '')
    .replace(/,?\s*cinematic\.?/gi, '')
    .replace(/\.\s*$/, '')
    .trim();
}

// ── Build structured prompt: slots joined, no labels, no negatives ──
function buildPrompt(scene, shotOverride, act) {
  const mood = ACT_MOOD[act] || ACT_MOOD.UNKNOWN;
  const cleanedScene = cleanScenePrompt(scene);
  const parts = [MEDIUM, mood.palette, cleanedScene];
  if (shotOverride) parts.push(shotOverride);
  parts.push(mood.lighting, TEXTURE, FORMAT);
  return parts.join('. ') + '.';
}

// ── Shot variants with continuity anchors ──
const SHOTS = {
  a: null,
  b: 'Same exact scene and location described above. Camera pushes in to extreme close-up of the most prominent foreground subject or object. Background elements remain consistent and visible in soft focus. Same lighting direction and color temperature',
  c: 'Same exact scene and location described above. Camera pulls back to wide establishing shot revealing full environment. Every described element visible in frame. Same lighting direction and color temperature'
};

// ── Canonical character asset map (pose_variant → filename) ──
const CANONICAL_MAP = {
  P1: 'tyroneStanding_armsBySide_transparent.png',
  P2: 'tyrone_Standing_armsCrossed_transparent.png',
  P3: 'tyroneFullBody_frontal_transparent.png',
  P4: 'tyroneFullBody_quarterTurn_transparent.png',
  P5: 'tyrone_flexing_biceps_transparent.png',
  P6: 'tyrone_crouching_transparent.png'
};

// ── Act mapping for B-roll ──
function normalizeAct(actStr) {
  if (!actStr) return 'UNKNOWN';
  if (actStr.includes('ACT 1')) return 'ACT_1';
  if (actStr.includes('ACT 2A')) return 'ACT_2A';
  if (actStr.includes('ACT 2B')) return 'ACT_2B';
  if (actStr.includes('ACT 2C')) return 'ACT_2C';
  if (actStr.includes('ACT 3A')) return 'ACT_3A';
  if (actStr.includes('ACT 3B')) return 'ACT_3B';
  return 'UNKNOWN';
}

// ── Variant builder ──
function buildVariants(scene) {
  const isChar = !!scene.pose_variant;
  const base = scene.visual_prompt;
  const sceneNum = String(scene.scene_number).padStart(3, '0');
  const act = normalizeAct(scene.act);

  // ── CHARACTER SCENES: generate 3 bg plate variants for compositing ──
  if (isChar) {
    const canonicalFile = CANONICAL_MAP[scene.pose_variant] || CANONICAL_MAP.P1;
    const cleanedBg = cleanScenePrompt(base) + ' — environment and atmosphere only, empty scene, no characters, no animals';
    const charShots = {
      'bg-a': { desc: 'primary-bg-plate', shot: null },
      'bg-b': { desc: 'close-up-bg-plate', shot: 'Same exact scene and location described above. Camera pushes in to tight framing suitable for close-up character overlay. Background details in soft focus. Same lighting direction and color temperature' },
      'bg-c': { desc: 'wide-bg-plate', shot: 'Same exact scene and location described above. Camera pulls back to wide establishing shot. Leave compositional space in lower-third for character overlay — keep visual weight in upper two-thirds. Same lighting direction and color temperature' }
    };
    return Object.entries(charShots).map(([id, config]) => ({
      episode_id: episodeId,
      scene_number: scene.scene_number,
      variant_id: id,
      variant_desc: config.desc,
      visual_prompt_full: buildPrompt(cleanedBg, config.shot, act),
      target_filename: `scene-${sceneNum}-${id}.png`,
      generation_status: 'ready_for_generation',
      scene_type: 'environment',
      act: act,
      pose_variant: scene.pose_variant || null,
      canonical_source: canonicalFile,
      generation_attempts: 0
    }));
  }

  // ── NON-CHARACTER SCENES: 3 variants (primary, close-up, wide) ──
  return Object.entries(SHOTS).map(([id, shotOverride]) => ({
    episode_id: episodeId,
    scene_number: scene.scene_number,
    variant_id: id,
    variant_desc: id === 'a' ? 'primary' : id === 'b' ? 'close-up' : 'wide',
    visual_prompt_full: buildPrompt(base, shotOverride, act),
    target_filename: `scene-${sceneNum}-${id}.png`,
    generation_status: 'ready_for_generation',
    scene_type: scene.scene_type === 'narration_stills' ? 'environment' : 'detail',
    act: act,
    pose_variant: null,
    canonical_source: null,
    generation_attempts: 0
  }));
}

// ── Per-Act B-Roll prompts ──
const BROLL_LIBRARY = {
  ACT_1: {
    mood: 'Dark, isolated, survival',
    prompts: [
      'City skyline at night, distant sodium vapor glow on low clouds, silhouetted buildings',
      'Rain falling on cracked concrete, pooling in uneven surface, sodium vapor light reflecting in puddles',
      'Chain-link fence shadow pattern cast by streetlight on empty sidewalk',
      'Sodium vapor streetlight pool of orange on empty wet asphalt, darkness beyond',
      'Empty urban street at 3am, single working streetlight, abandoned storefronts',
      'Heavy padlock on rusted chain-link gate, peeling paint, night',
      'Cracked concrete wall with water stains, harsh side-lighting',
      'Distant emergency lights glow reflecting off wet street, no vehicles visible',
      'Wet asphalt reflecting sodium vapor orange, shallow puddles, tire tracks',
      'Lone streetlight illuminating empty intersection, deep shadows all around',
      'Abandoned lot with weeds through concrete, chain-link perimeter, night',
      'Rooftop edge silhouette against distant city glow, dark foreground'
    ]
  },
  ACT_2A: {
    mood: 'Wry, observational',
    prompts: [
      'Neon check-cashing sign reflected in wet window, urban night',
      'Surveillance camera mounted on brick corner, harsh overhead light',
      'Liquor store neon signs glowing through dirty glass, iron security bars',
      'Sidewalk cracks in extreme close-up, weeds pushing through, sodium light',
      'Empty bus stop bench under flickering fluorescent shelter light',
      'Graffiti wall in deep shadow, single spray-painted tag illuminated by distant light',
      'Bodega awning dripping rain, neon OPEN sign casting red glow on wet sidewalk'
    ]
  },
  ACT_2B: {
    mood: 'Warm, building',
    prompts: [
      'Warm kitchen light spilling through window onto dark exterior wall',
      'Barbershop interior details — leather chair, mirror, warm incandescent light',
      'Golden hour light on urban street, long shadows, warm tones breaking through steel',
      'Concrete stoop with single potted plant, warm light from doorway behind',
      'Dog-eared paperback book open on worn wooden surface, warm lamplight',
      'Coffee steam rising in morning light, cup on windowsill, city visible outside',
      'Warm light through curtain, casting soft pattern on interior wall'
    ]
  },
  ACT_2C: {
    mood: 'Conviction, community',
    prompts: [
      'Community garden plot with young plants, chain-link fence, early morning light',
      'Railroad tracks converging to vanishing point, dawn light on horizon',
      'Community bulletin board covered in flyers and notices, pin-light illumination',
      'Sunrise over rooftops, warm orange breaking through dark steel sky',
      'Open book pages in warm directional light, text blurred, moody',
      'Single candle flame in dark room, warm glow on surrounding surfaces',
      'Hands holding open book, close-up, warm light, no face visible'
    ]
  },
  ACT_3A: {
    mood: 'Historical, reverent',
    prompts: [
      'Old photograph edges curling, sepia tones, on dark wooden surface',
      'Candlelight flickering on brick wall, warm shadows, reverent mood',
      'Worn book pages extreme close-up, yellowed paper, printed text, soft focus',
      'Old brick building facade, historical architecture, overcast light',
      'Church steeple silhouette against dusk sky, muted colors',
      'Archive texture — stacked old documents, leather binding, dust particles in light beam'
    ]
  },
  ACT_3B: {
    mood: 'Confident, practical',
    prompts: [
      'Laptop screen glow in dim room, code or course interface visible, modern',
      'Food truck service window at night, warm interior light, menu board',
      'Apartment windows grid pattern at night, various warm lights in each',
      'Online course interface on screen, progress bar, clean modern design',
      'Garden harvest — fresh vegetables in wooden crate, golden hour light',
      'City panorama from elevated position, dawn, possibility and scale',
      'Stack of books beside laptop, warm desk lamp, study setup',
      'Hand writing in notebook, close-up, warm lamplight, no face'
    ]
  }
};

// ── Process all scenes ──
const allRecords = [];
const stats = { character: 0, environment: 0, detail: 0, remotion: 0, transition: 0, reuse: 0, broll: 0 };

for (const scene of scenes) {
  if (!scene.visual_prompt || scene.visual_backend !== 'gemini') {
    if (scene.visual_backend === 'remotion') stats.remotion++;
    else if (!scene.visual_prompt && !scene.visual_backend) stats.transition++;
    continue;
  }

  const variants = buildVariants(scene);
  const type = variants[0].scene_type;
  stats[type] = (stats[type] || 0) + variants.length;
  allRecords.push(...variants);
}

// ── Add B-Roll records (same structured template) ──
for (const [act, data] of Object.entries(BROLL_LIBRARY)) {
  data.prompts.forEach((prompt, idx) => {
    const brollNum = String(idx + 1).padStart(2, '0');
    const actLower = act.toLowerCase().replace('_', '');
    allRecords.push({
      episode_id: episodeId,
      scene_number: null,
      variant_id: brollNum,
      variant_desc: `broll-${data.mood.toLowerCase().split(',')[0].trim()}`,
      visual_prompt_full: buildPrompt(prompt, null, act),
      target_filename: `broll-${actLower}-${brollNum}.png`,
      generation_status: 'ready_for_generation',
      scene_type: 'broll',
      act: act,
      pose_variant: null,
      generation_attempts: 0
    });
    stats.broll++;
  });
}

return allRecords.map(record => ({ json: record }));

const allItems = $('Airtable — Create Record').all();
const episodeId = allItems[0]?.json?.episode_id || 'unknown';

// Count by scene_type
const counts = {};
for (const item of allItems) {
  const type = item.json.scene_type || item.json.fields?.scene_type || 'unknown';
  counts[type] = (counts[type] || 0) + 1;
}

const summary = {
  status: 'complete',
  episode_id: episodeId,
  total_records_created: allItems.length,
  counts_by_type: counts,
  completed_at: new Date().toISOString()
};

return [{ json: summary }];
